class WebAppBridge(
    private val activity: MainActivity,
    private val webView: WebView
) {
    private val sharedPreferences = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
    private var notificationId = 1000

    fun injectBridgeScript() {
        val script = """
            window.NativeBridge = window.NativeBridge || {};
            window.NativeBridge.callbacks = {};
            window.NativeBridge.callbackId = 0;
            
            window.NativeBridge.call = function(method, params, callback) {
                var callbackId = this.callbackId++;
                if (callback) {
                    this.callbacks[callbackId] = callback;
                }
                var message = JSON.stringify({
                    method: method,
                    params: params || {},
                    callbackId: callbackId
                });
                window.NativeBridge.handleMessage(message);
            };
            
            window.NativeBridge.handleCallback = function(callbackId, result) {
                if (this.callbacks[callbackId]) {
                    this.callbacks[callbackId](result);
                    delete this.callbacks[callbackId];
                }
            };
        """.trimIndent()

        activity.runOnUiThread {
            webView.evaluateJavascript(script, null)
        }
    }

    @JavascriptInterface
    fun handleMessage(message: String) {
        try {
            val json = JSONObject(message)
            val method = json.getString("method")
            val params = json.optJSONObject("params") ?: JSONObject()
            val callbackId = json.getInt("callbackId")

            when (method) {
                "requestCameraPermission" -> requestCameraPermission(callbackId)
                "requestNotificationPermission" -> requestNotificationPermission(callbackId)
                "showNotification" -> showNotification(params, callbackId)
                "saveToStorage" -> saveToStorage(params, callbackId)
                "getFromStorage" -> getFromStorage(params, callbackId)
                "removeFromStorage" -> removeFromStorage(params, callbackId)
                "clearStorage" -> clearStorage(callbackId)
                "showToast" -> showToast(params, callbackId)
                "vibrate" -> vibrate(params, callbackId)
                "getDeviceInfo" -> getDeviceInfo(callbackId)
                else -> sendCallback(callbackId, createError("Unknown method: $method"))
            }
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    private fun requestCameraPermission(callbackId: Int) {
        activity.runOnUiThread {
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) 
                == PackageManager.PERMISSION_GRANTED) {
                sendCallback(callbackId, createSuccess(true))
            } else {
                pendingCallbacks[callbackId] = "camera"
                activity.requestCameraPermission()
            }
        }
    }

    private fun requestNotificationPermission(callbackId: Int) {
        activity.runOnUiThread {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                if (ContextCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) 
                    == PackageManager.PERMISSION_GRANTED) {
                    sendCallback(callbackId, createSuccess(true))
                } else {
                    pendingCallbacks[callbackId] = "notification"
                    activity.requestNotificationPermission()
                }
            } else {
                sendCallback(callbackId, createSuccess(true))
            }
        }
    }

    private fun showNotification(params: JSONObject, callbackId: Int) {
        activity.runOnUiThread {
            try {
                val title = params.optString("title", "Notification")
                val message = params.optString("message", "")
                val priority = params.optInt("priority", NotificationCompat.PRIORITY_DEFAULT)

                val builder = NotificationCompat.Builder(activity, "webapp_channel")
                    .setSmallIcon(android.R.drawable.ic_dialog_info)
                    .setContentTitle(title)
                    .setContentText(message)
                    .setPriority(priority)
                    .setAutoCancel(true)

                with(NotificationManagerCompat.from(activity)) {
                    if (ActivityCompat.checkSelfPermission(
                            activity,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) == PackageManager.PERMISSION_GRANTED
                    ) {
                        notify(notificationId++, builder.build())
                        sendCallback(callbackId, createSuccess(true))
                    } else {
                        sendCallback(callbackId, createError("Notification permission not granted"))
                    }
                }
            } catch (e: Exception) {
                sendCallback(callbackId, createError(e.message ?: "Failed to show notification"))
            }
        }
    }

